const url = $("Route by Content Type").first().json.message.text

const match = url.match(/(?:youtube\.com\/(?:watch\?v=|shorts\/|embed\/)|youtu\.be\/)([a-zA-Z0-9_-]{11})/);
const videoId = match ? match[1] : null;

return [{ json: { ...$input.item.json, videoId } }];

const data = JSON.parse($input.item.json.text);

const stanceEmoji = {
  buy: '🟢', sell: '🔴', trim: '🟡', add: '🟢',
  avoid: '🔴', conviction_change: '🔵', hold: '⚪'
};

let lines = ['Signals stored ✅', ''];

if (data.sectors && data.sectors.length > 0) {
  data.sectors.forEach(s => {
    lines.push(`🏦 *${s.sector}* — ${s.direction}`);
    if (s.verbatim_quote) lines.push(`_${s.verbatim_quote}_`);
    if (s.reasoning) lines.push(s.reasoning);
    lines.push('');
  });
}

for (const stock of data.stocks) {
  const emoji = stanceEmoji[stock.stance] || '⚪';
  lines.push(`${emoji} *${stock.stock_name}* — ${stock.stance}`);
  lines.push(`_${stock.verbatim_quote}_`);
  lines.push(stock.reasoning);
  lines.push('');
}

lines.push(`📊 ${data.market_tone}`);

return [{ json: { telegramReply: lines.join('\n') } }];

const data = JSON.parse($input.first().json.text);

const source_id = $("Store Source Metadata").first().json.source_id;
const channel = $("Store Source Metadata").first().json.channel;
const input_type = $("Store Source Metadata").first().json.input_type;

let doc_date;
try { doc_date = $("Prepare PDF Data").first().json.doc_date; } catch(e) {}
try { if (!doc_date) doc_date = $("Prepare YouTube Data").first().json.doc_date; } catch(e) {}

const stockRows = (data.stocks || []).map(stock => ({
  json: {
    pageContent: `Stock: ${stock.stock_name} | Stance: ${stock.stance} | Channel: ${channel} | Date: ${doc_date} | ${stock.verbatim_quote} ${stock.reasoning}`,
    metadata: {
      source_id,
      channel,
      doc_date,
      input_type,
      stock_name: stock.stock_name,
      stance: stock.stance
    }
  }
}));

const sectorRows = (data.sectors || []).map(sector => ({
  json: {
    pageContent: `Sector: ${sector.sector} | Direction: ${sector.direction} | Channel: ${channel} | Date: ${doc_date} | ${sector.verbatim_quote} ${sector.reasoning}`,
    metadata: {
      source_id,
      channel,
      doc_date,
      input_type,
      stock_name: sector.sector,
      stance: sector.direction
    }
  }
}));

const allRows = [...stockRows, ...sectorRows];

if (allRows.length === 0) {
  return [{ json: { skip: true, noSignals: true } }];
}

return allRows;
